package distribution.release.samples.oauth.client.demo.oauth.client.controllers;

@ Controller public class CallbackURLController { @ RequestMapping ( "/callback" ) protected ModelAndView handleRequest ( @ ModelAttribute ( "oAuthParams" ) OAuthParams oAuthParams , HttpServletRequest request ) throws Exception { OAuthMessage message = OAuthServlet . getMessage ( request , request . getRequestURL ( ) . toString ( ) ) ; try { message . requireParameters ( OAuth . OAUTH_TOKEN , OAuth . OAUTH_VERIFIER ) ; oAuthParams . setOauthToken ( message . getToken ( ) ) ; oAuthParams . setOauthVerifier ( message . getParameter ( OAuth . OAUTH_VERIFIER ) ) ; oAuthParams . setClientID ( Common . findCookieValue ( request , "clientID" ) ) ; oAuthParams . setClientSecret ( Common . findCookieValue ( request , "clientSecret" ) ) ; } catch ( OAuthProblemException e ) { oAuthParams . setErrorMessage ( "OAuth problem: " + e . getProblem ( ) + e . getParameters ( ) . toString ( ) ) ; } return new ModelAndView ( "tokenRequest" ) ; } }